\displaystyle{\begin{aligned}[t]
    \frac{5}{6} \div \left(-\frac{7}{4}\right)
        \amp = \frac{5}{6} \cdot \left(-\frac{4}{7}\right) \amp \hbox{We can divide the first denominator and the second numerator by 2.}\\
        \amp = \frac{5}{3 }\cdot\left(-\frac{2}{7}\right) \\
        \amp = -\frac{10}{21}
\end{aligned}
    }
